% 将图像转换为double类型
img = im2double(img);

% 获取图像的尺寸
[height, width, ~] = size(img);

% 调整H和S值到[0,1]范围内，I值到[0,0.8]范围内
img(:,:,1) = img(:,:,1)/360; % 色调
img(:,:,2) = img(:,:,2)/100; % 饱和度
img(:,:,3) = img(:,:,3)*0.8; % 亮度

