[X,Y,Z] = cylinder(img(:,:,3), height);

% 定义H和S网格
[H,S] = meshgrid(linspace(0,1,width), linspace(0,1,height));

% 计算圆柱体上每个点的颜色
R = interp2(H,S,img(:,:,1),X,Y) * 255;
G = interp2(H,S,img(:,:,2),X,Y) * 255;
B = interp2(H,S,img(:,:,3),X,Y) * 255;

% 创建圆柱体图像
figure;
surf(X,Y,Z,cat(3,R,G,B)/255);
title('Cylindrical Representation of HSI Color Space');
xlabel('x');
ylabel('y');
zlabel('Intensity');
colorbar;
view(3);
```

