function result = find_convex_region(data, row, col)
    [rows, cols] = size(data);
    visited = false(rows, cols);
    queue = [row, col];

    while ~isempty(queue)
        current = queue(1, :);
        queue(1, :) = [];
        r = current(1);
        c = current(2);

        if r > 0 && r <= rows && c > 0 && c <= cols && ~visited(r, c)
            visited(r, c) = true;
            if data(r, c) >= data(row, col)
                queue = [queue; [r-1, c]; [r+1, c]; [r, c-1]; [r, c+1]];
            end
        end
    end

    result = visited;
end
```

