```matlab
function region = find_peak_region(matrix, peak_row, peak_col, threshold)
    [rows, cols] = size(matrix);
    visited = false(rows, cols);
    region = false(rows, cols);
    stack = [peak_row, peak_col];

    while ~isempty(stack)
        current = stack(end, :);
        stack(end, :) = [];
        r = current(1);
        c = current(2);

        if r > 0 && r <= rows && c > 0 && c <= cols && ~visited(r, c) && abs(matrix(r, c) - matrix(peak_row, peak_col)) <= threshold
            visited(r, c) = true;
            region(r, c) = true;
            stack = [stack; [r-1, c]; [r+1, c]; [r, c-1]; [r, c+1]];
        end
    end
end

